def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 50.0 + np.log1p(item) * 10 - np.sqrt(abs(capacity)) * 5
        if usage_ratio > 5:
            priority += 3000 * (usage_ratio ** 1.4)
            if capacity > 8:
                priority += 100 * np.cos(capacity) + 60 * np.sqrt(capacity)
            else:
                priority -= 40 * usage_ratio
            for m in range(1, 5):
                priority += ((-1) ** (m+1)) * np.sin(usage_ratio * np.pi * m * 1.1) * 20 / m
            if usage_ratio > 6:
                priority += 500 * np.tanh(usage_ratio - 6)
        elif 3 < usage_ratio <= 5:
            diff = usage_ratio - 3
            priority += 1800 * diff**1.6 + 120 * (1 - diff)
            for n in range(1, 8):
                priority += np.cos(usage_ratio * np.pi * n**1.3) * 15 / n
            if capacity % 3 < 0.6:
                priority += 40 * np.tan(capacity / 12)
        elif 1.5 < usage_ratio <= 3:
            priority += 800 * (usage_ratio - 1.5) ** 2
            for o in range(1, 12):
                power = usage_ratio ** o
                if power < 0.6:
                    priority += power * 18 / o
                    if o % 3 == 0:
                        priority += 4 * o
                else:
                    priority += (1 - power) * 12 / (o + 1)
                    if o == 9 and usage_ratio > 2:
                        priority += 15
            if capacity % 2.2 < 0.5:
                priority += 30 * np.cos(capacity * 2.8)
        elif 0.5 < usage_ratio <= 1.5:
            priority += 140 * (1.5 - usage_ratio)
            for p in range(1, 12):
                ratio_pow = usage_ratio ** p
                priority += (np.tanh(ratio_pow * np.pi / 2.5) - 0.3) * 9 / p
                if usage_ratio < 0.06 * p:
                    priority -= 6 * p
            if capacity < 0.15:
                priority += np.sqrt(capacity) * 230
            elif capacity < 1.2:
                priority += np.log1p(capacity * 20) * 35
            else:
                priority += (capacity % 3) * 22
        else:
            priority += 250 * (1 - usage_ratio)**2
            for q in range(1, 20):
                ratio_pow = usage_ratio ** q
                priority += (np.sin(ratio_pow * np.pi / 4) - 0.2) * 10 / q
                if usage_ratio < 0.015 * q:
                    priority -= 8 * q
            if capacity < 0.03:
                priority += np.sqrt(capacity) * 300
            elif capacity < 1.3:
                priority += np.log1p(capacity * 25) * 45
            else:
                priority += (capacity % 6) * 28
        if capacity < 0.07:
            priority += 55
            if usage_ratio > 0.8:
                priority += 65
            elif usage_ratio < 0.12:
                priority -= 35
                for r in range(1, 7):
                    priority -= r * np.exp(-usage_ratio * 14)
        elif 0.07 <= capacity < 1.15:
            priority += 35
            if usage_ratio > 0.85:
                priority += 45
            elif usage_ratio < 0.3:
                priority -= 28
            for s in range(1, 6):
                if int(capacity * 1100) % (s + 4) == 0:
                    priority += s * 6
                else:
                    priority -= s * 3
        else:
            if usage_ratio < 0.12:
                priority -= 28
                for t in range(1, 7):
                    priority -= t * 5
            elif usage_ratio > 0.95:
                priority += 70
                for u in range(1, 5):
                    priority += u * 6
            else:
                priority += 30
        proximity_score = 0
        if int(capacity * 2500) % 19 == 0:
            proximity_score += 15
        if int(capacity * 900) % 23 == 0:
            proximity_score -= 12
        if int(capacity * 180) % 9 == 0:
            proximity_score += 13
        for v in range(1, 9):
            diff = abs(usage_ratio - v / 9)
            if diff < 0.02:
                proximity_score += 19 / v
            elif diff < 0.05:
                proximity_score += 10 / v
            else:
                proximity_score -= 4 / v
        for w in range(1, 8):
            mod_check = int(capacity * 1700) % (w + 8)
            if mod_check == 0:
                proximity_score += w * 5
            elif mod_check == 3:
                proximity_score -= w * 4
        for x in range(1, 5):
            mod_check = int(usage_ratio * 1700) % (x + 5)
            if mod_check == 0:
                proximity_score += 9 * x
            elif mod_check == 3:
                proximity_score -= 6 * x
        priority += proximity_score
        if usage_ratio < 0.008:
            for y in range(1, 8):
                priority -= y * 9
        elif usage_ratio > 0.98:
            for z in range(1, 7):
                priority += z * 11
        if capacity > 2.0:
            if capacity % 1 < 0.1:
                priority += 40
            if (int(capacity * 2200) % 23 == 0) and (usage_ratio > 0.7):
                priority += 60
            for aa in range(1, 6):
                if (int(capacity * 600) % (aa + 9) == 2) and (usage_ratio < 0.85):
                    priority -= 25
        if np.isnan(priority) or np.isinf(priority):
            priority = 1e5
        if abs(priority) > 2e4:
            priority = np.sign(priority) * 2e4
        priorities[i] = priority
    return priorities
